UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('countermovement-vertical-jump', 'Jump-and-stick, low volume, no max testing language.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('squat-jump', 'Use squat-to-stand fast or low jump-to-stick.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('broad-jump-to-stick', 'Small broad jump to stick, focus on quiet landing.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('single-broad-jump-to-rebound', 'Not recommended; use broad jump to stick.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('lateral-bound-to-stick', 'Lateral step-to-stick or small hop-to-stick.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('skater-bound-continuous', 'Use lateral bound to stick or lateral step.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('split-jump-scissor-jump', 'Split squat hold or split squat to calf raise.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-chest-pass', 'Very light ball, partner pass, 2–3 reps at a time.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-overhead-slam', 'Light soft ball, low reps, teach overhead position.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-rotational-scoop-toss', 'Light ball, half-kneeling or tall-kneeling toss to teach trunk path.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-shot-put-throw', 'Light ball standing chest-pass angle; avoid heavy shot-put mechanics.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

INSERT INTO coaching.exercise_scaling_profile (exercise_id, cohort_key, label, scale_direction, load_guidance, gender_specific_notes)
