  ('split-jump-scissor-jump', 'Split squat hold or split squat to calf raise.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-chest-pass', 'Very light ball, partner pass, 2–3 reps at a time.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-overhead-slam', 'Light soft ball, low reps, teach overhead position.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-rotational-scoop-toss', 'Light ball, half-kneeling or tall-kneeling toss to teach trunk path.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-shot-put-throw', 'Light ball standing chest-pass angle; avoid heavy shot-put mechanics.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.')
