  ('medicine-ball-overhead-slam', 'Use light ball and avoid aggressive bracing/pressure if inappropriate.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-rotational-scoop-toss', 'Use low-intensity rotational pattern only if appropriate; avoid aggressive bracing/twisting.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-shot-put-throw', 'Use low-intensity push throw only if appropriate; avoid aggressive bracing/rotation.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum';

INSERT INTO coaching.exercise_scaling_profile (exercise_id, cohort_key, label, scale_direction, load_guidance, gender_specific_notes)
SELECT e.id, 'pregnancy_postpartum', 'pregnancy postpartum', 'baseline', v.guidance,
  CASE WHEN 'pregnancy_postpartum' = 'adult_beginner' THEN v.gender_notes ELSE NULL END
FROM (VALUES
  ('countermovement-vertical-jump', 'Usually avoid maximal jumping unless specifically cleared and highly accustomed; use low-impact power alternatives.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('squat-jump', 'Usually avoid maximal jumping; use lower-impact power variation if appropriate.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('broad-jump-to-stick', 'Usually avoid max horizontal jumping; use step-to-stick or low-impact power.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('single-broad-jump-to-rebound', 'Not recommended.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('lateral-bound-to-stick', 'Use side step or lateral lunge shift only if appropriate.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('skater-bound-continuous', 'Not recommended at Output intensity.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('split-jump-scissor-jump', 'Usually avoid split jumps; use supported split stance power step.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-chest-pass', 'Use light ball, avoid aggressive bracing/pressure if not appropriate.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-overhead-slam', 'Use light ball and avoid aggressive bracing/pressure if inappropriate.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-rotational-scoop-toss', 'Use low-intensity rotational pattern only if appropriate; avoid aggressive bracing/twisting.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.'),
  ('medicine-ball-shot-put-throw', 'Use low-intensity push throw only if appropriate; avoid aggressive bracing/rotation.', 'No default sex-based adjustment. Scale by landing quality, body mass, training age, tissue tolerance, throw velocity, and injury history rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.exercise_scaling_profile sp
  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum'
);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Express jump and throw power while fresh — low volume, high intent, generous rest, clean landings.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('countermovement-vertical-jump', 'The countermovement jump uses a rapid dip before the upward jump, which allows the athlete to use the stretch-shortening cycle and higher joint moments before takeoff. Bobbert et al. found that countermovement jumps can exceed squat jumps in height because the countermovement helps the athlete attain greater joint moments at the start of push-off.', 'Belongs in vertical_jump_power (341) — primary Output vertical power drill after elastic rudiments and landing prep.', 'Primary vertical power drill after elastic rudiments and landing prep; before squat jump comparison or horizontal power work.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. Do not turn into repeated jump conditioning. Stop when height or landing quality drops.', 'Regress to jump-and-stick or submax CMJ; progress to measured reps when landing stays quiet and aligned.'),
  ('squat-jump', 'The squat jump starts from a stationary squat position, which reduces the countermovement and emphasizes concentric force production from the start posture. This makes it different from the countermovement jump, where a quick downward movement precedes takeoff.', 'Belongs in vertical_jump_power (341) — concentric vertical power complement to countermovement jump; true pause required.', 'After or paired with countermovement vertical jump when concentric-only vertical power is the goal; requires true pause.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. If athlete dips again before takeoff, classify as countermovement jump, not squat jump.', 'Regress to squat-to-stand fast or low jump-to-stick; progress to measured squat jump with strict no-countermovement rule.'),
  ('broad-jump-to-stick', 'The broad jump expresses horizontal projection and landing control. It is useful for athletes who need acceleration, jumping, and horizontal force qualities because it trains the athlete to project the center of mass forward and then absorb force safely. As with all jump progressions, landing mechanics should be mastered before distance becomes the priority; The Prehab Guys'' jump fundamentals material highlights landing mechanics and confidence as prerequisites for jump progression.', 'Belongs in horizontal_jump_power (342) — primary horizontal projection drill with mandatory stick landing.', 'Primary horizontal power drill after vertical jump or landing prep; before single broad jump to rebound.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. Stick quality is non-negotiable — do not progress to rebound until broad jump stick is consistent.', 'Regress to small broad jump to stick; reduce distance intent until 2-second freeze is automatic.'),
  ('single-broad-jump-to-rebound', 'This progression takes the horizontal projection of the broad jump and adds a second elastic contact. It is more demanding than a broad jump to stick because the athlete must absorb and reapply force quickly rather than simply stop. That makes it a bridge from horizontal power into reactive strength and sprint-like projection.', 'Belongs in horizontal_jump_power (342) — SSC bridge after broad jump stick; requires horizontal landing competency.', 'After broad jump to stick is consistent; bridges horizontal power into elastic re-application.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. Rebound should not be added until first landing is controlled. Do not jump too far on first contact.', 'Regress to broad jump to stick; use smaller first jump until rebound stays aligned and crisp.'),
  ('lateral-bound-to-stick', 'The lateral bound trains frontal-plane power and single-leg landing control. The Prehab Guys describe lateral bound variations as shifting weight to one leg, jumping to the side, landing on the opposite leg, and pausing until balanced before returning. Physitrack''s skater-jump description similarly emphasizes generating force with the arms, extending the ankle/knee/hip, landing softly on the lead leg, pausing until balanced, then bounding the other direction.', 'Belongs in lateral_jump_power (343) — single-leg frontal-plane power with mandatory stick before continuous skater bounds.', 'After lateral line hops and single-leg balance; before skater bound continuous.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. Stick before distance — do not progress to continuous skater bounds until freeze is consistent.', 'Regress to lateral step-to-stick or small hop-to-stick; use target cone and short bound distance.'),
  ('skater-bound-continuous', 'Continuous skater bounds progress from "jump and stick" to repeated side-to-side force application. The Prehab Guys'' continuous lateral bound description starts from single-leg balance, hops laterally to the other leg, sticks the landing, and repeats in the other direction. This drill belongs in Output only when the athlete can maintain rhythm, frontal-plane control, and landing quality across repeated contacts.', 'Belongs in lateral_jump_power (343) — repeated lateral power after lateral bound stick; rhythm over distance.', 'After lateral bound to stick is clean; late lateral power progression in jump/throw block.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. Continuous version should not be used until lateral bound stick is consistent. Do not chase width over control.', 'Regress to lateral bound to stick; cap total contacts and stop when rhythm or landing quality drops.'),
  ('split-jump-scissor-jump', 'The scissor jump trains reciprocal lower-body power and coordination. The Prehab Guys describe the scissor lunge as starting in split stance, pushing off both feet to jump, switching foot position in the air, and landing in control. A low-depth split squat jump variation can reduce range and emphasize quick but soft contacts when athletes are not ready for large split-switch jumps.', 'Belongs in split_jump_power (344) — reciprocal lower-body power requiring split-stance landing control.', 'After split squat and lunge landing competency; reciprocal power block before or after horizontal jumps.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. Do not use as high-rep conditioning in Output. Control before speed on leg switch.', 'Regress to split squat hold or split jump without switching; progress to scissor only when split landing is clean.'),
  ('medicine-ball-chest-pass', 'Medicine-ball throws are useful for power because the athlete can release the implement and express high velocity rather than decelerating a load like in many traditional lifts. NSCA describes medicine-ball throws as a way to assess or train core/power qualities, and medicine-ball training has been discussed as a practical method for explosive sport-specific power development.', 'Belongs in upper_body_power (345) — ballistic upper-body push without repeated jump landing stress.', 'Upper-body power entry in jump/throw block; pairs with rotational throws after lower-body jumps or elastic work.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. Ball too heavy or slow push is Capacity, not Output. Heavy slow throws are not this card.', 'Regress to partner pass with very light ball; progress to step-behind or reactive chest pass when velocity stays high.'),
  ('medicine-ball-overhead-slam', 'The overhead slam lets the athlete express total-body power by coordinating overhead reach, trunk bracing, hip action, and forceful arm drive into a ballistic release. Medicine-ball training is commonly used to train dynamic power because it allows explosive movement patterns to be performed with an implement that can be released or slammed.', 'Belongs in total_body_power (346) — total-body ballistic expression without repeated jump landing stress.', 'Total-body power drill after vertical jumps or between upper-body throw pairs; requires slam-safe ball.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. High-rep slams become conditioning. Power drill only if reps stay explosive.', 'Regress to light soft ball overhead throw; reduce overhead range if rib flare or lumbar extension appears.'),
  ('medicine-ball-rotational-scoop-toss', 'Rotational medicine-ball throws let athletes train explosive rotation with an implement they can release, which makes the movement more ballistic and sport-relevant than many slow trunk exercises. Earp and Kraemer note that medicine-ball training allows complex sport-specific movements to be performed explosively with greater resistance than regular sport actions. Eric Cressey''s split-stance medicine-ball scoop discussion also emphasizes hip/trunk separation through thoracic mobility rather than excessive low-back motion.', 'Belongs in rotational_power (347) — hip-trunk rotational power with light fast ball; ground-up force transfer.', 'Rotational power entry after anti-rotation prep; before shot-put throw or sport-specific rotational block.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. Rotating through low back instead of hips/thoracic spine. Ball too heavy slows throw — not Output.', 'Regress to half-kneeling or tall-kneeling scoop; progress to split-stance or step-behind when throw stays fast and clean.'),
  ('medicine-ball-shot-put-throw', 'The shot-put throw trains explosive single-side rotational pushing. It is useful for athletes who need to transfer force from the ground through the hips and trunk into the upper body. Medicine-ball work is frequently used for rotational power because it permits explosive sport-like patterns with external load and release.', 'Belongs in rotational_power (347) — single-side explosive push/rotation complement to scoop toss.', 'After rotational scoop toss or anti-rotation prep; single-side explosive transfer in rotational power block.', 'Jump, throw & explosive power belong in Output while the athlete is fresh — high intent, low reps, generous rest, clean landings, and fast throws. Power work should look powerful. Do not use as conditioning, high-volume jump circuits, or fatigue work when height, distance, throw speed, or landing quality drops. Do not overload ball so throw slows — that shifts toward Capacity. Arm-only throw misses hip-trunk transfer.', 'Regress to half-kneeling or split-stance shot-put; progress to step-behind when throw velocity stays high.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Jump / throw power cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'output_jump_power_readiness',
  NULL,
  'Jump, Throw & Explosive Power without pre-fatigue',
  'Jump and medicine-ball Output requires high intent, low reps, generous rest, clean landings, and fast throws — not conditioning volume.',
  'Output jump/throw cards 28–38 express vertical, horizontal, lateral, split-stance, upper-body, total-body, and rotational power while the athlete is fresh.',
  'Power work should look powerful. When height, distance, throw speed, rhythm, or landing quality drops, the session is no longer Output — it is fatigue or capacity work with higher injury risk.',
  'Keep reps low, rest generous, landings clean, and throws fast. Use Broad Jump to Stick before rebound variants, Lateral Bound to Stick before continuous skater bounds, and light balls for velocity.',
  'Do not program jump/throw Output after conditioning, with high rep jump circuits, heavy slow medicine balls, or when landing mechanics fail — regress dose or change phase intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
